import { HttpClient } from "@angular/common/http";
import { Component, Inject, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { EnvService } from "src/app/core/services/env.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { IGender } from "../../Models/References/Gender";
import { Policy } from "../../Models/Users/Policy";
import { UserInfo } from "src/app/core/models/UserInfo";
import { FeaturesAuthService } from "src/app/core/services/AuthenticationServices/features-auth.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import {
  UserBranch,
  BranchReference,
} from "../../Models/Settings/BranchReference";
import { IOfficer, officerResponseModal } from "../../Models/Officer/Officer";
import { OfficerService } from "src/app/core/services/officer.service";
import { AlertService } from "src/app/core/services/alert.service";
import { User } from "../../Models/Permissions/User";
import { AlertController, ModalController } from "@ionic/angular";
import { DOCUMENT, DatePipe } from "@angular/common";
import { TranslateService } from "@ngx-translate/core";
import { UserDataInfo } from "../../Models/Users/UserDataInfo";
import { format } from "date-fns";
@Component({
  selector: "app-change-password",
  templateUrl: "./change-password.page.html",
  styleUrls: ["./change-password.page.css"],
})
export class ChangePasswordPage implements OnInit {
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private referencesService: ReferencesService,
    private FormBuilder: FormBuilder,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    private OfficerService: OfficerService,
    private alertController: AlertController,
    private modal: ModalController,
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    public translate: TranslateService,
    @Inject(DOCUMENT) private document: Document
  ) {}

  Genders: IGender[];

  Policy: Policy[];
  BRData: BranchReference[];
  userInfo: UserInfo;
  Officer: officerResponseModal[];
  PersonalFormValid: Boolean;
  isVisible: Boolean;
  selectedUser: User;
  UserDataInfo: UserDataInfo;
  PromiseOff: Promise<officerResponseModal[]>;
  personalForm: FormGroup = this.FormBuilder.group({
    user_name: [null, [Validators.required]],
    full_name: [null],
    password: [null, [Validators.required]],
    re_password: [null, [Validators.required]],
  });

  personalFormStatus: boolean = false;
  showLoader = false;
  async ngOnInit(): Promise<void> {
    this.Genders = await this.referencesService.getGender();
    this.userInfo = await this.authService.getUserInfo();
    this.PersonalFormValid = false;
    this.getOfficersByBranchCode();
    this.personalFormStatus = true;
    this.GetuserPolicy(Number(this.userInfo.org_code));
    this.GetbranchByUser(this.userInfo.user_name);
    this.isVisible = false;
  }

  userSelected(user: User): void {
    console.log("ssssss");
    this.isVisible = true;
    this.selectedUser = user;
    this.showLoader = true;
    this.http
      .get<UserDataInfo>(
        this.env.API_URL + `api/User/GetUserInfo?user_name=${user.user_name}`
      )
      .subscribe({
        next: (data) => {
          this.UserDataInfo = data;
          console.log("ssd", this.UserDataInfo.officerkey);
          this.personalForm.patchValue({
            user_name: this.UserDataInfo.user_name,
            full_name: this.UserDataInfo.full_name,
          });

          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.message);
          this.showLoader = false;
        },
      });
  }

  DeselectUser() {
    this.selectedUser = null;
  }

  async GetuserPolicy(org_code: number) {
    //this.showLoader = true;
    this.Policy = await this.http
      .get<Policy[]>(
        this.env.API_URL + `api/Policy/GetuserPolicy?org_code=` + org_code
      )
      .toPromise();
    console.log("Test", this.Policy);
  }

  async GetbranchByUser(user_name: string) {
    //this.showLoader = true;
    this.BRData = await this.http
      .get<BranchReference[]>(
        this.env.API_URL + `api/Branch/GetbranchByUser?user_name=` + user_name
      )
      .toPromise();
    console.log("Test", this.Policy);
  }

  getOfficersByBranchCode = async (): Promise<officerResponseModal[]> => {
    try {
      console.log("br", this.personalForm.value.userBrcode);
      this.showLoader = true;
      const response = await this.http
        .get<officerResponseModal[]>(
          this.env.API_URL +
            `api/Officer/GetBranchOfficers?branch_code=${this.personalForm.value.userBrcode}`,
          {}
        )
        .toPromise();
      {
        this.Officer = response;
      }
      this.showLoader = false;

      return response;
    } catch (error) {
      console.error("Error", error);
      throw error;
    }
  };

  async SaveUser() {
    this.PersonalFormValid = true;
    if (
      this.personalForm.value.password == this.personalForm.value.re_password
    ) {
      if (this.personalForm.valid) {
        this.http
          .post(this.env.API_URL + "api/User/ChangePassword", {
            user_name: this.personalForm.value.user_name,
            password: this.personalForm.value.password,
          })
          .subscribe({
            next: (data) => {
              this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertService.showAlertError(err.error, false);
            },
          });
      }
    } else {
      this.alertService.showAlertConfirm("كلمة المرور غير متطابقة", false);
    }
  }
  async BackUser() {
    this.PersonalFormValid = false;
    this.personalFormStatus = true;
    this.DeselectUser();
    this.isVisible = false;
  }
}
